Url":"https://maps.google.com"}],"story":[{"year":"2019","title":"Pertama Bertemu","text":"Kami dipertemukan dalam sebuah acara kampus, berawal dari obrolan sederhana yang tak terlupakan."},{"year":"2021","title":"Menjalin Hubungan","text":"Setelah saling mengenal, kami memutuskan untuk melangkah bersama menjalani hari demi hari."},{"year":"2025","title":"Lamaran","text":"Dengan restu kedua keluarga, Bimo melamar Sekar dalam suasana yang hangat dan penuh haru."},{"year":"2026","title":"Menuju Pelaminan","text":"Kini kami siap menyempurnakan separuh agama, dan berharap doa restu dari Anda semua."}],"gallery":["foto1.jpg","foto2.jpg","foto3.jpg","foto4.jpg","foto5.jpg","foto6.jpg"],"banks":[{"bank":"Bank BCA","number":"1234 5678 90","holder":"a.n. Sekar Ayu Pramesti"},{"bank":"Bank Mandiri","number":"0987 6543 21","holder":"a.n. Bimo Arya Nugraha"}],"info":[{"icon":"👗","title":"Dress Code","text":"Nuansa earth tone & pastel — sage green, dusty pink, cream."},{"icon":"🅿️","title":"Parkir","text":"Area parkir luas tersedia di dalam gedung dan sekitarnya."},{"icon":"🎁","title":"Angpao","text":"Tersedia kotak angpao di dekat pintu masuk resepsi."}],"thanks":{"eyebrow":"Terima Kasih","message":"Merupakan suatu kebahagiaan dan kehormatan bagi kami apabila Bapak/Ibu/Saudara/i berkenan hadir dan memberikan doa restu.","closing":"Wassalamu’alaikum Warahmatullahi Wabarakatuh","credit":"Kel. Bapak Suryanto · Kel. Bapak Hendra &nbsp;|&nbsp; Made with ❀"},"share":{"waText":"Assalamualaikum. Dengan penuh kebahagiaan, kami mengundang Bapak/Ibu/Saudara/i ke pernikahan Sekar & Bimo. Info lengkap & konfirmasi kehadiran: "},"integrations":{"sheetEndpoint":"","storageKey":"wishes_sekar_bimo"}}'::jsonb)
